#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-02.
"""
Build a virtual-best results JSON: for each benchmark filename, pick the stats dict
from whichever of the five runs has the lowest numeric "scq". Ties break on source
basename (lexicographic).

Usage:
    python3 virtual_best.py [RESULTS_DIR]

Writes RESULTS_DIR/virtual_best.json by default.

Requires every file in SOURCE_RESULT_JSON to exist under RESULTS_DIR.
"""

from __future__ import annotations

import copy
import json
import sys
from pathlib import Path
from typing import Any

SOURCE_RESULT_JSON = (
    "control.json",
    "heuristic_ac.json",
    "heuristic_no_ac.json",
    "optimal_ac.json",
    "optimal_no_ac.json",
)

VIRTUAL_BEST_BASENAME = "virtual_best.json"
VIRTUAL_BEST_ENTRY_KEY = "virtual-best"


def is_numeric(x: Any) -> bool:
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def extract_stats_blob(entry: dict[str, Any]) -> dict[str, Any]:
    blobs = [
        v
        for k, v in entry.items()
        if k != "filename" and isinstance(v, dict)
    ]
    if not blobs:
        return {}
    if len(blobs) > 1:
        merged: dict[str, Any] = {}
        for b in blobs:
            merged.update(b)
        return merged
    return blobs[0]


def load_by_filename(path: Path) -> dict[str, dict[str, Any]]:
    data = json.loads(path.read_text(encoding="utf-8"))
    out: dict[str, dict[str, Any]] = {}
    for entry in data.get("results", []):
        fn = entry.get("filename")
        if not fn:
            continue
        stats = extract_stats_blob(entry)
        if stats:
            out[str(fn)] = stats
    return out


def compute_virtual_best(results_dir: Path) -> dict[str, Any]:
    """
    For each filename appearing in any source run, choose the stats blob with minimum scq
    among runs that have a numeric scq for that filename.
    """
    results_dir = results_dir.resolve()
    per_file: dict[str, list[tuple[float, str, dict[str, Any]]]] = {}
    for basename in SOURCE_RESULT_JSON:
        path = results_dir / basename
        by_fn = load_by_filename(path)
        for fn, stats in by_fn.items():
            if "scq" not in stats or not is_numeric(stats["scq"]):
                continue
            scq = float(stats["scq"])
            per_file.setdefault(fn, []).append(
                (scq, basename, copy.deepcopy(stats))
            )

    merged_results: list[dict[str, Any]] = []
    for fn in sorted(per_file.keys()):
        candidates = per_file[fn]
        if not candidates:
            continue
        _scq, _src, best_stats = min(candidates, key=lambda t: (t[0], t[1]))
        merged_results.append(
            {"filename": fn, VIRTUAL_BEST_ENTRY_KEY: best_stats}
        )

    return {"results": merged_results}


def write_virtual_best(
    results_dir: Path,
    output_basename: str | None = None,
) -> Path | None:
    """
    Write virtual best JSON. Returns output path, or None if any source file is missing.
    """
    results_dir = results_dir.resolve()
    out_name = output_basename or VIRTUAL_BEST_BASENAME
    missing = [b for b in SOURCE_RESULT_JSON if not (results_dir / b).is_file()]
    if missing:
        print(
            "virtual_best: missing source file(s), not writing output: "
            + ", ".join(missing),
            file=sys.stderr,
        )
        return None
    payload = compute_virtual_best(results_dir)
    out_path = results_dir / out_name
    out_path.write_text(json.dumps(payload, indent=2) + "\n", encoding="utf-8")
    return out_path


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    results_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else script_dir / "results"
    results_dir = results_dir.resolve()
    if not results_dir.is_dir():
        print(f"Not a directory: {results_dir}", file=sys.stderr)
        return 1
    out = write_virtual_best(results_dir)
    if out is None:
        return 1
    print(f"Wrote {out}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
